const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const API_SECRET = process.env.API_SECRET || 'change-me';

const levels = new Map([
  [1, { baseReward: 100, targetScore: 1000, targetTime: 120 }],
  [2, { baseReward: 150, targetScore: 1500, targetTime: 150 }],
  [3, { baseReward: 200, targetScore: 2000, targetTime: 180 }],
  [4, { baseReward: 250, targetScore: 2500, targetTime: 210 }],
  [5, { baseReward: 300, targetScore: 3000, targetTime: 240 }]
]);

const players = new Map();

function getPlayer(playerId) {
  if (!players.has(playerId)) {
    players.set(playerId, {
      completedLevels: new Set(),
      claimedRewards: new Set(),
      balance: 0,
      history: []
    });
  }
  return players.get(playerId);
}

function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

function computeReward(levelConfig, score, timeSeconds) {
  const scoreRatio = clamp(score / levelConfig.targetScore, 0, 2);
  const timeRatio = clamp(levelConfig.targetTime / Math.max(timeSeconds, 1), 0, 2);
  const performanceMultiplier = clamp((scoreRatio + timeRatio) / 2, 0.5, 2);
  return Math.floor(levelConfig.baseReward * performanceMultiplier);
}

function signPayload(payload) {
  return crypto.createHmac('sha256', API_SECRET).update(JSON.stringify(payload)).digest('hex');
}

function verifySignature(req, res, next) {
  const signature = req.header('x-signature');
  if (!signature) return res.status(401).json({ error: 'Missing signature' });

  const bodyString = JSON.stringify(req.body || {});
  const expected = crypto.createHmac('sha256', API_SECRET).update(bodyString).digest('hex');

  if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  next();
}

app.post('/api/level/complete', verifySignature, (req, res) => {
  const { playerId, levelId, score, timeSeconds } = req.body || {};

  if (!playerId || typeof playerId !== 'string') {
    return res.status(400).json({ error: 'Invalid playerId' });
  }
  if (!Number.isInteger(levelId) || !levels.has(levelId)) {
    return res.status(400).json({ error: 'Invalid levelId' });
  }
  if (!Number.isFinite(score) || score < 0) {
    return res.status(400).json({ error: 'Invalid score' });
  }
  if (!Number.isFinite(timeSeconds) || timeSeconds <= 0) {
    return res.status(400).json({ error: 'Invalid timeSeconds' });
  }

  const player = getPlayer(playerId);
  const levelConfig = levels.get(levelId);

  const reward = computeReward(levelConfig, score, timeSeconds);
  const completionKey = `${levelId}`;

  if (!player.completedLevels.has(completionKey)) {
    player.completedLevels.add(completionKey);
    player.balance += reward;
    player.history.push({
      type: 'level_complete',
      levelId,
      score,
      timeSeconds,
      reward,
      createdAt: new Date().toISOString()
    });
  }

  const response = {
    ok: true,
    playerId,
    levelId,
    score,
    timeSeconds,
    reward,
    balance: player.balance,
    signature: signPayload({ playerId, levelId, score, timeSeconds, reward })
  };

  res.json(response);
});

app.post('/api/rewards/claim', verifySignature, (req, res) => {
  const { playerId, rewardId, amount } = req.body || {};

  if (!playerId || typeof playerId !== 'string') {
    return res.status(400).json({ error: 'Invalid playerId' });
  }
  if (!rewardId || typeof rewardId !== 'string') {
    return res.status(400).json({ error: 'Invalid rewardId' });
  }
  if (!Number.isFinite(amount) || amount <= 0) {
    return res.status(400).json({ error: 'Invalid amount' });
  }

  const player = getPlayer(playerId);
  const claimKey = `${rewardId}`;

  if (player.claimedRewards.has(claimKey)) {
    return res.status(409).json({ error: 'Reward already claimed' });
  }

  if (player.balance < amount) {
    return res.status(400).json({ error: 'Insufficient balance' });
  }

  player.claimedRewards.add(claimKey);
  player.balance -= amount;
  player.history.push({
    type: 'reward_claim',
    rewardId,
    amount,
    createdAt: new Date().toISOString()
  });

  res.json({
    ok: true,
    playerId,
    rewardId,
    amount,
    balance: player.balance,
    signature: signPayload({ playerId, rewardId, amount })
  });
});

app.get('/api/player/:playerId', (req, res) => {
  const { playerId } = req.params;
  const player = getPlayer(playerId);

  res.json({
    playerId,
    balance: player.balance,
    completedLevels: Array.from(player.completedLevels).map(Number),
    claimedRewards: Array.from(player.claimedRewards),
    history: player.history
  });
});

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.listen(PORT, () => {
  console.log(`API listening on port ${PORT}`);
});